const SUBJECTS = {
  chem: { label: "AP Chemistry", unitLabel: "Unit 5: Kinetics", sections: CHEM_SECTIONS },
  bio: { label: "AP Biology", unitLabel: "Unit 5: Heredity", sections: BIO_SECTIONS },
};


const INK = "#1F2A24";
const PAPER = "#F6F2E7";
const GREEN = "#2F6F5E";
const RUST = "#A6432D";
const AMBER = "#C8912B";
const LINE = "#D9D2C0";

function Ring({ pct, size = 140 }) {
  const stroke = 12;
  const r = (size - stroke) / 2;
  const c = 2 * Math.PI * r;
  const off = c - (pct / 100) * c;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={LINE} strokeWidth={stroke} />
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={GREEN} strokeWidth={stroke}
        strokeDasharray={c} strokeDashoffset={off} strokeLinecap="round"
        transform={`rotate(-90 ${size / 2} ${size / 2})`} style={{ transition: "stroke-dashoffset 0.8s ease" }} />
      <text x="50%" y="50%" textAnchor="middle" dy="0.35em" style={{ fontFamily: "Georgia, serif", fontSize: 26, fill: INK, fontWeight: 700 }}>{pct}%</text>
    </svg>
  );
}

export default function App() {
  const [subject, setSubject] = useState("chem"); // chem | bio
  const [screen, setScreen] = useState("home"); // home | student | quiz | report
  const [student, setStudent] = useState({ name: "", email: "" });
  const [studentDraft, setStudentDraft] = useState({ name: "", email: "" });
  const [sectionIdx, setSectionIdx] = useState(0);
  const [answers, setAnswers] = useState({});
  const [filter, setFilter] = useState("all");
  const [submitState, setSubmitState] = useState("idle"); // idle | sending | sent | error

  const subjectData = SUBJECTS[subject];
  const section = subjectData.sections[sectionIdx];
  const qs = section.questions;

  function pick(id, idx) { setAnswers((a) => ({ ...a, [id]: idx })); }

  const results = useMemo(() => qs.map((q) => {
    const given = answers[q.id];
    const unanswered = given === undefined;
    const correct = !unanswered && given === q.answer;
    return { ...q, given, unanswered, correct };
  }), [answers, qs]);

  const score = results.filter((r) => r.correct).length;
  const wrong = results.filter((r) => !r.correct && !r.unanswered).length;
  const blank = results.filter((r) => r.unanswered).length;
  const pct = Math.round((score / qs.length) * 100);

  const filtered = results.filter((r) => {
    if (filter === "correct") return r.correct;
    if (filter === "incorrect") return !r.correct && !r.unanswered;
    return true;
  });

  function switchSubject(s) {
    setSubject(s);
    setSectionIdx(0);
    setScreen("home");
  }

  function startSection(i) {
    setSectionIdx(i);
    setAnswers({});
    setSubmitState("idle");
    setStudentDraft({ name: "", email: "" });
    setStudent({ name: "", email: "" });
    setScreen("student");
  }

  function submitStudentInfo() {
    if (!studentDraft.name.trim() || !studentDraft.email.trim()) return;
    setStudent(studentDraft);
    setScreen("quiz");
  }

  // Auto-send the graded result to the teacher's Google Sheet when the report screen opens.
  useEffect(() => {
    if (screen !== "report") return;
    if (!SHEET_ENDPOINT) { setSubmitState("idle"); return; }
    setSubmitState("sending");
    const payload = {
      name: student.name,
      email: student.email,
      subject: subjectData.label,
      unit: `Unit ${section.id} - ${section.title}`,
      score: score,
      total: qs.length,
      percent: pct,
      correct: score,
      incorrect: wrong,
      unanswered: blank,
      timestamp: new Date().toLocaleString("ko-KR"),
    };
    fetch(SHEET_ENDPOINT, {
      method: "POST",
      mode: "no-cors",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams(payload).toString(),
    })
      .then(() => setSubmitState("sent"))
      .catch(() => setSubmitState("error"));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [screen]);

  return (
    <div style={{ background: PAPER, minHeight: "100vh", color: INK, fontFamily: "Georgia, 'Times New Roman', serif" }}>
      <div className="max-w-3xl mx-auto px-6 py-10">
        <div className="flex items-baseline justify-between mb-6 pb-4" style={{ borderBottom: `2px solid ${INK}` }}>
          <div>
            <div className="text-[11px] uppercase tracking-[0.2em]" style={{ fontFamily: "ui-monospace, monospace", color: GREEN }}>
              ChemBio with Yoo · Unit Quiz
            </div>
            <h1 className="text-3xl font-bold mt-1">{subjectData.label} — {subjectData.unitLabel}</h1>
          </div>
        </div>

        {screen === "home" && (
          <div>
            <div className="flex gap-2 mb-6">
              {Object.entries(SUBJECTS).map(([key, s]) => (
                <button key={key} onClick={() => switchSubject(key)}
                  className="px-5 py-2.5 text-sm font-bold uppercase tracking-wide"
                  style={{
                    border: `1.5px solid ${INK}`,
                    background: subject === key ? INK : "transparent",
                    color: subject === key ? PAPER : INK,
                    borderRadius: 3,
                  }}>
                  {s.label}
                </button>
              ))}
            </div>
            <p className="mb-4 leading-relaxed" style={{ color: "#4A4438" }}>
              각 섹션 시작 시 이름/이메일을 입력합니다.
            </p>
            <div className="space-y-4">
              {subjectData.sections.map((s, i) => (
                <button key={s.id} onClick={() => startSection(i)}
                  className="w-full text-left p-5 flex justify-between items-center"
                  style={{ border: `1px solid ${LINE}`, borderRadius: 4, background: "#FFFEFB" }}>
                  <div>
                    <div className="text-xs font-bold uppercase tracking-wide" style={{ color: GREEN }}>Unit {s.id}</div>
                    <div className="font-bold text-lg">{s.title}</div>
                  </div>
                  <span className="text-sm" style={{ color: "#8A8270" }}>{s.questions.length}문항 →</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {screen === "student" && (
          <div>
            <div className="text-xs font-bold uppercase tracking-wide mb-2" style={{ color: GREEN }}>{subjectData.label} · Unit {section.id} · {section.title}</div>
            <p className="mb-6 leading-relaxed" style={{ color: "#4A4438" }}>
              이 섹션을 풀기 전에 이름과 이메일을 입력해주세요. 채점 결과는 선생님께 자동으로 전달됩니다.
            </p>
            <div className="space-y-4 max-w-sm">
              <div>
                <label className="block text-xs font-bold uppercase tracking-wide mb-1" style={{ color: GREEN }}>이름</label>
                <input
                  type="text"
                  value={studentDraft.name}
                  onChange={(e) => setStudentDraft((s) => ({ ...s, name: e.target.value }))}
                  placeholder="Enter name"
                  className="w-full px-3 py-2 text-sm"
                  style={{ border: `1.5px solid ${LINE}`, borderRadius: 3, background: "#FFFEFB" }}
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-wide mb-1" style={{ color: GREEN }}>이메일</label>
                <input
                  type="email"
                  value={studentDraft.email}
                  onChange={(e) => setStudentDraft((s) => ({ ...s, email: e.target.value }))}
                  placeholder="name@example.com"
                  className="w-full px-3 py-2 text-sm"
                  style={{ border: `1.5px solid ${LINE}`, borderRadius: 3, background: "#FFFEFB" }}
                />
              </div>
              <button
                onClick={submitStudentInfo}
                disabled={!studentDraft.name.trim() || !studentDraft.email.trim()}
                className="px-6 py-3 font-bold text-sm uppercase tracking-wide"
                style={{
                  background: studentDraft.name.trim() && studentDraft.email.trim() ? INK : LINE,
                  color: PAPER,
                  borderRadius: 3,
                  cursor: studentDraft.name.trim() && studentDraft.email.trim() ? "pointer" : "not-allowed",
                }}
              >
                시작하기 →
              </button>
              <button
                onClick={() => setScreen("home")}
                className="ml-3 px-4 py-3 text-sm font-bold uppercase tracking-wide"
                style={{ border: `1.5px solid ${INK}`, borderRadius: 3, background: "transparent" }}
              >
                ← 목록으로
              </button>
            </div>
          </div>
        )}

        {screen === "quiz" && (
          <div>
            <div className="text-xs font-bold uppercase tracking-wide mb-4" style={{ color: GREEN }}>{subjectData.label} · Unit {section.id} · {section.title}</div>
            <div className="space-y-6 mb-8">
              {qs.map((q, i) => (
                <div key={q.id} className="p-5" style={{ border: `1px solid ${LINE}`, borderRadius: 4, background: "#FFFEFB" }}>
                  <div className="flex items-center gap-2 mb-3">
                    <span className="text-xs font-bold" style={{ fontFamily: "ui-monospace, monospace", color: GREEN }}>Q{i + 1}</span>
                  </div>
                  <p className="mb-3 leading-relaxed">{q.text}</p>
                  {q.image && (
                    <img src={q.image} alt={`${q.id} data`} className="mb-4 max-w-full rounded" style={{ border: `1px solid ${LINE}` }} />
                  )}
                  <div className="space-y-2">
                    {q.choices.map((c, ci) => (
                      <button key={ci} onClick={() => pick(q.id, ci)}
                        className="w-full text-left px-4 py-2 text-sm flex gap-3"
                        style={{
                          border: `1.5px solid ${answers[q.id] === ci ? GREEN : LINE}`,
                          background: answers[q.id] === ci ? "rgba(47,111,94,0.08)" : "transparent",
                          borderRadius: 3,
                        }}>
                        <span className="font-bold" style={{ color: GREEN }}>{String.fromCharCode(65 + ci)}</span>
                        <span>{c}</span>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            <div className="flex gap-3">
              <button onClick={() => setScreen("home")} className="px-5 py-2.5 text-sm font-bold uppercase tracking-wide" style={{ border: `1.5px solid ${INK}`, borderRadius: 3 }}>← 목록</button>
              <button onClick={() => setScreen("report")} className="px-6 py-3 font-bold text-sm uppercase tracking-wide" style={{ background: INK, color: PAPER, borderRadius: 3 }}>제출하고 채점하기</button>
            </div>
          </div>
        )}

        {screen === "report" && (
          <div>
            <div className="mb-4 text-xs font-bold uppercase tracking-wide" style={{ color: "#8A8270" }}>
              {student.name} · {student.email}
            </div>
            {SHEET_ENDPOINT ? (
              <div className="mb-4 px-3 py-2 text-xs" style={{
                borderRadius: 3,
                background: submitState === "sent" ? "rgba(47,111,94,0.1)" : submitState === "error" ? "rgba(166,67,45,0.1)" : "#F1ECDD",
                color: submitState === "sent" ? GREEN : submitState === "error" ? RUST : "#8A8270",
              }}>
                {submitState === "sending" && "채점 결과를 선생님 시트로 전송 중..."}
                {submitState === "sent" && "✓ 채점 결과가 선생님께 전송되었습니다."}
                {submitState === "error" && "전송 실패 — 네트워크를 확인해주세요. (화면 점수는 그대로 유효합니다)"}
              </div>
            ) : null}
            <div className="flex items-center gap-8 mb-8 p-6" style={{ border: `1px solid ${LINE}`, borderRadius: 4, background: "#FFFEFB" }}>
              <Ring pct={pct} />
              <div className="flex gap-6">
                <div><div className="text-2xl font-bold" style={{ color: GREEN }}>{score}</div><div className="text-xs uppercase" style={{ color: "#8A8270" }}>정답</div></div>
                <div><div className="text-2xl font-bold" style={{ color: RUST }}>{wrong}</div><div className="text-xs uppercase" style={{ color: "#8A8270" }}>오답</div></div>
                <div><div className="text-2xl font-bold" style={{ color: AMBER }}>{blank}</div><div className="text-xs uppercase" style={{ color: "#8A8270" }}>미응답</div></div>
              </div>
            </div>

            <div className="flex gap-2 mb-5 flex-wrap">
              {["all", "correct", "incorrect"].map((f) => (
                <button key={f} onClick={() => setFilter(f)}
                  className="px-3 py-1.5 text-xs font-bold uppercase tracking-wide"
                  style={{ border: `1px solid ${INK}`, background: filter === f ? INK : "transparent", color: filter === f ? PAPER : INK, borderRadius: 3 }}>
                  {{ all: "전체", correct: "정답", incorrect: "오답" }[f]}
                </button>
              ))}
            </div>

            <div className="space-y-5">
              {filtered.map((r) => (
                <div key={r.id} className="p-5" style={{ border: `1px solid ${LINE}`, borderRadius: 4, background: "#FFFEFB" }}>
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-xs font-bold px-2 py-0.5" style={{
                      color: PAPER,
                      background: r.unanswered ? AMBER : r.correct ? GREEN : RUST,
                      borderRadius: 2,
                    }}>
                      {r.unanswered ? "미응답" : r.correct ? "정답" : "오답"}
                    </span>
                  </div>
                  <p className="mb-3 leading-relaxed">{r.text}</p>
                  {r.image && (
                    <img src={r.image} alt={`${r.id} data`} className="mb-3 max-w-full rounded" style={{ border: `1px solid ${LINE}` }} />
                  )}
                  <div className="space-y-1 text-sm mb-3">
                    {r.choices.map((c, ci) => (
                      <div key={ci} className="px-3 py-1.5" style={{
                        borderRadius: 3,
                        background: ci === r.answer ? "rgba(47,111,94,0.1)" : r.given === ci ? "rgba(166,67,45,0.08)" : "transparent",
                      }}>
                        <span className="font-bold mr-2" style={{ color: ci === r.answer ? GREEN : INK }}>{String.fromCharCode(65 + ci)}</span>{c}
                      </div>
                    ))}
                  </div>
                  <div className="text-xs leading-relaxed whitespace-pre-line" style={{ color: "#5C5648", background: "#F1ECDD", padding: "10px 12px", borderRadius: 3 }}>{r.note}</div>
                </div>
              ))}
            </div>

            <button onClick={() => setScreen("home")} className="mt-8 px-5 py-2.5 text-sm font-bold uppercase tracking-wide" style={{ border: `1.5px solid ${INK}`, borderRadius: 3 }}>↺ 다른 섹션 풀기</button>
          </div>
        )}
      </div>
    </div>
  );
}
